import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestClientBuilder;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.data.elasticsearch.client.ClientConfiguration;
import org.springframework.data.elasticsearch.client.Destinations;
import org.springframework.data.elasticsearch.client.TransportClientFactoryBean;

@Configuration
public class ElasticsearchConfig {

    @Value("${elasticsearch.url}")
    private String elasticsearchUrl;

    @Value("${elasticsearch.username}")
    private String elasticsearchUsername;

    @Value("${elasticsearch.password}")
    private String elasticsearchPassword;

    @Bean
    public RestHighLevelClient restHighLevelClient() {
        ClientConfiguration clientConfiguration = ClientConfiguration.builder()
                .connectedTo(elasticsearchUrl)
                .build();

        Destinations destinations = Destinations.create(clientConfiguration);

        TransportClientFactoryBean factoryBean = new TransportClientFactoryBean(destinations);
        factoryBean.setHttpClientConfigCallback(httpClientBuilder -> httpClientBuilder
                .setDefaultCredentialsProvider(new DefaultCredentialsProvider())
                .setSSLContext(getSSLContext()));

        return factoryBean.getObject();
    }

    private SSLContext getSSLContext() {
        try {
            KeyStore keyStore = KeyStore.getInstance("PKCS12");
            keyStore.load(getClass().getResourceAsStream("/elasticsearch-cert.p12"), "changeit".toCharArray());

            TrustManagerFactory trustManagerFactory = TrustManagerFactory.getInstance(TrustManagerFactory.getDefaultAlgorithm());
            trustManagerFactory.init((KeyStore) null);

            SSLContext sslContext = SSLContexts.custom()
                    .loadTrustMaterial(keyStore, (chain, authType) -> true)
                    .build();

            return sslContext;
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @Bean
    public ElasticsearchTemplate elasticsearchTemplate() {
        return new ElasticsearchTemplate(restHighLevelClient());
    }

    @Bean
    public ProductRepository productRepository(ElasticsearchTemplate elasticsearchTemplate) {
        return new ProductRepository(elasticsearchTemplate);
    }

    public class ProductRepository {

        private final ElasticsearchTemplate elasticsearchTemplate;

        public ProductRepository(ElasticsearchTemplate elasticsearchTemplate) {
            this.elasticsearchTemplate = elasticsearchTemplate;
        }

        public void saveProduct(Product product) {
            IndexRequest indexRequest = new IndexRequest("products")
                    .source(product, XContentType.JSON);

            elasticsearchTemplate.index(indexRequest);
        }
    }

    @Bean
    public SearchService searchService(ElasticsearchTemplate elasticsearchTemplate) {
        return new SearchService(elasticsearchTemplate);
    }

    public class SearchService {

        private final ElasticsearchTemplate elasticsearchTemplate;

        public SearchService(ElasticsearchTemplate elasticsearchTemplate) {
            this.elasticsearchTemplate = elasticsearchTemplate;
        }

        public List<Product> searchProducts(String query, String[] facets) {
            SearchQuery searchQuery = new SearchQuery(query, facets);

            SearchHits hits = elasticsearchTemplate.queryForPage(searchQuery, "products", 0, 10).getSearchHits();

            return hits.map(hit -> hit.getSourceAs(Product.class)).toList();
        }
    }

    public class SearchQuery {

        private final String query;
        private final String[] facets;

        public SearchQuery(String query, String[] facets) {
            this.query = query;
            this.facets = facets;
        }
    }
}